import{_ as a,c as t,o as n,ag as s}from"./chunks/framework.DD2hp6gW.js";const i="/assets/settings-advanced-delete-data.Dl343W6T.png",l="/assets/settings-advanced-license.0kt6S_WQ.png",m=JSON.parse('{"title":"Advanced Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/advanced-settings.md","filePath":"settings/advanced-settings.md","lastUpdated":null}'),o={name:"settings/advanced-settings.md"};function c(r,e,d,h,u,g){return n(),t("div",null,e[0]||(e[0]=[s('<h1 id="advanced-settings" tabindex="-1">Advanced Settings <a class="header-anchor" href="#advanced-settings" aria-label="Permalink to &quot;Advanced Settings&quot;">​</a></h1><p>The <strong>Advanced Settings</strong> tab contains options for data management and license activation.</p><h2 id="data-management" tabindex="-1">Data Management <a class="header-anchor" href="#data-management" aria-label="Permalink to &quot;Data Management&quot;">​</a></h2><h3 id="delete-all-data-on-uninstall" tabindex="-1">Delete All Data on Uninstall <a class="header-anchor" href="#delete-all-data-on-uninstall" aria-label="Permalink to &quot;Delete All Data on Uninstall&quot;">​</a></h3><p><img src="'+i+'" alt="Delete All Data on Uninstall"></p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>This is a destructive action. Only enable this if you want to completely remove all CampaignBay data.</p></div><ul><li><strong>Checked:</strong> When you uninstall the plugin, a cleanup script will <strong>permanently delete</strong> all associated database tables and options.</li><li><strong>Unchecked:</strong> Your campaign data will be preserved if you reinstall the plugin later.</li></ul><hr><h2 id="license-management" tabindex="-1">License Management <a class="header-anchor" href="#license-management" aria-label="Permalink to &quot;License Management&quot;">​</a></h2><p><img src="'+l+'" alt="License Key"></p><h3 id="license-key" tabindex="-1">License Key <a class="header-anchor" href="#license-key" aria-label="Permalink to &quot;License Key&quot;">​</a></h3><p>Enter the license key you received upon purchase of CampaignBay Pro.</p><h3 id="activate-license" tabindex="-1">Activate License <a class="header-anchor" href="#activate-license" aria-label="Permalink to &quot;Activate License&quot;">​</a></h3><p>Click to validate your key and unlock Pro features. Once activated, your license status will show as active.</p><h3 id="deactivate-license" tabindex="-1">Deactivate License <a class="header-anchor" href="#deactivate-license" aria-label="Permalink to &quot;Deactivate License&quot;">​</a></h3><p>If you need to migrate your license to another domain, click <strong>Deactivate License</strong> to release it from the current site before activating on a new one.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you&#39;ve configured your settings, head to the FAQ for common questions and answers.</p><ul><li><strong><a href="./../faq.html">FAQ →</a></strong></li></ul>',20)]))}const v=a(o,[["render",c]]);export{m as __pageData,v as default};
